module alu
(
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output carry,
    output negative,
    output overflow,
    output flag
);
    parameter ADD = 6'b100000;
    parameter ADDU = 6'b100001;
    parameter SUB = 6'b100010;
    parameter SUBU = 6'b100011;
    parameter AND = 6'b100100;
    parameter OR = 6'b100101;
    parameter XOR = 6'b100110;
    parameter NOR = 6'b100111;
    parameter SLT = 6'b101010;
    parameter SLTU = 6'b101011;
    parameter SLL = 6'b000000;
    parameter SRL = 6'b000010;
    parameter SRA = 6'b000011;
    parameter SLLV = 6'b000100;
    parameter SRLV = 6'b000110;
    parameter SRAV = 6'b000111;
    parameter LUI = 6'b001111;

    reg [32:0] res;

    assign r = res[31:0];
    assign zero = res[31:0] == 0;
    assign carry = res[32];
    assign negative = res[31];
    assign overflow = res[31] ^ res[30];
    assign flag = res[31] ^ res[30];
    always @(*) begin
        case (aluc)
            ADD: res = $signed(a) + $signed(b);
            ADDU: res = a + b;
            SUB: res = $signed(a) - $signed(b);
            SUBU: res = a - b;
            AND: res = {1'b0, a & b};
            OR: res = {1'b0, a | b};
            XOR: res = {1'b0, a ^ b};
            NOR: res = {1'b0, ~(a | b)};
            SLT: res = {1'b0, $signed(a) < $signed(b)};
            SLTU: res = {1'b0, a < b};
            SLL: res = {a, b[4:0]};
            SRL: res = {a, b[4:0]} >> b[4:0];
            SRA: res = $signed(a) >>> b[4:0];
            SLLV: res = {a, b[4:0]};
            SRLV: res = {a, b[4:0]} >> b[4:0];
            SRAV: res = $signed(a) >>> b[4:0];
            LUI: res = {b[15:0], 16'b0};
            default: res = 33'b0;
        endcase
    end
endmodule
